import{_ as o,H as a,f as t,i}from"./chunks/framework.nN4pLK1d.js";const u=JSON.parse('{"title":"Loops","description":"","frontmatter":{},"headers":[],"relativePath":"packages/rcml/email/concepts/advanced/loops.md","filePath":"packages/rcml/email/concepts/advanced/loops.md"}'),l={name:"packages/rcml/email/concepts/advanced/loops.md"};function r(n,e,c,s,d,p){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1>Loops</h1><p><code>&lt;rc-loop&gt;</code> renders a block of email content once per item in a data feed — news feed, remote URL, custom field, or XML source. The loop&#39;s child <code>rc-section</code> is duplicated for each item, up to a configurable maximum.</p><p>Without loops, a &quot;recommended products&quot; section featuring five items would require five separately-authored sections, each manually configured with a product image, name, and link. When the product data changes, every section needs updating. A loop describes the section structure once; the renderer fills it in from the feed at send time.</p><h2 id="loop-variables" tabindex="-1">Loop variables <a class="header-anchor" href="#loop-variables" aria-label="Permalink to &quot;Loop variables&quot;">​</a></h2><p>Inside the loop, individual fields from the current item are inserted using <code>::loop-value</code> atoms in <code>rc-text</code> and <code>rc-heading</code> content. A <code>loop-value</code> atom identifies its data source by the <code>loop-value</code> attribute of the enclosing <code>rc-loop</code>, and the specific field by an index name — for example, a news item&#39;s title, image URL, or link.</p><h2 id="personalization-and-limits" tabindex="-1">Personalization and limits <a class="header-anchor" href="#personalization-and-limits" aria-label="Permalink to &quot;Personalization and limits&quot;">​</a></h2><p>A <code>loop-type=&quot;remote-content&quot;</code> loop fetches data from a URL, and that URL can contain <code>[Subscriber:...]</code> and <code>[CustomField:...]</code> tokens that are resolved per recipient before the request is made. This enables personalized feeds — each subscriber sees items relevant to their history — without pre-generating per-subscriber content.</p><p><code>loop-max-iterations</code> prevents emails from growing uncontrollably. A news feed may have 200 articles; a product catalog could have thousands. Without a cap, the compiled email could become enormous and trigger spam filters or delivery failures. Set a limit that matches the design intent (typically 3–10 items for a newsletter block).</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/control-flow/rc-loop.html"><code>&lt;rc-loop&gt;</code> reference</a> — attributes, source types, and examples</li><li><a href="/rule-io-sdk/latest/packages/rcml/email/content/inline-nodes/loop-value.html"><code>loop-value</code> node</a> — the inline atom used inside loop content</li></ul>',10)])])}const h=o(l,[["render",r]]);export{u as __pageData,h as default};
